  1→import { Box, Text } from "ink";
  2→import type { DisplayMessage, DisplayItem } from "../api.js";
  3→import {
  4→  formatDuration,
  5→  formatTokens,
  6→  truncate,
  7→  roleColor,
  8→  roleIcon,
  9→  formatJson,
 10→} from "../lib/format.js";
 11→import { colors, getItemColor, getTeamColor } from "../lib/theme.js";
 12→import { getItemIcon, getItemName, getItemSummary } from "../lib/items.js";
 13→import { StatsBar, statsFromMessage } from "./StatsBar.js";
 14→import { BrailleSpinner, OngoingDot } from "./OngoingDots.js";
 15→import { stableWindow } from "../lib/window.js";
 16→import {
 17→  IconExpanded,
 18→  IconCollapsed,
 19→  IconBarSingle,
 20→  IconBarDouble,
 21→  IconSelected2,
 22→  IconHRule,
 23→} from "../lib/icons.js";
 24→
 25→/** Max content width — matches Go TUI's maxContentWidth. */
 26→const MAX_CONTENT_WIDTH = 160;
 27→
 28→/** Limit text to maxLines while preserving newlines. Appends "…" if truncated. */
 29→function limitLines(text: string, maxLines: number): string {
 30→  const lines = text.split("\n");
 31→  if (lines.length <= maxLines) return text;
 32→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
 33→}
 34→
 35→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
 36→function clampLines(text: string, maxWidth: number): string {
 37→  return text
 38→    .split("\n")
 39→    .map((line) => (line.length > maxWidth ? line.slice(0, maxWidth - 1) + "…" : line))
 40→    .join("\n");
 41→}
 42→
 43→interface DetailViewProps {
 44→  message: DisplayMessage;
 45→  selectedItem: number;
 46→  expandedItems: Set<number>;
 47→  ongoing: boolean;
 48→  depth?: number;
 49→}
 50→
 51→function itemBorderColor(item: DisplayItem, isSelected: boolean): string {
 52→  if (isSelected) return colors.accent;
 53→  // Subagent items with messages get their team color
 54→  if (item.subagent_messages.length > 0 && item.team_color) {
 55→    return getTeamColor(item.team_color);
 56→  }
 57→  return getItemColor(item.item_type, !!item.tool_error);
 58→}
 59→
 60→export function DetailView({
 61→  message,
 62→  selectedItem,
 63→  expandedItems,
 64→  ongoing,
 65→  depth = 0,
 66→}: DetailViewProps) {
 67→  const cols = process.stdout.columns || 80;
 68→  const contentWidth = Math.min(cols, MAX_CONTENT_WIDTH);
 69→  const stats = statsFromMessage(message);
 70→  const items = message.items;
 71→
 72→  // InfoBar(3) + KeybindBar(3) + header box(3) + padding = ~10 lines of chrome
 73→  const windowSize = Math.max(3, (process.stdout.rows || 24) - 10);
 74→  const { start, end } = stableWindow("detail", selectedItem, items.length, windowSize);
 75→  const visible = items.slice(start, end);
 76→
 77→  // Fixed-width name column — computed from ALL items so it doesn't shift (matches Go TUI's 12-char pad)
 78→  const maxNameLen = Math.max(12, ...items.map((it) => getItemName(it).length));
 79→
 80→  return (
 81→    <Box flexDirection="column">
 82→      {/* Message header — round border (matches Go TUI's RoundedBorder) */}
 83→      <Box flexDirection="column" borderStyle="round" borderColor={colors.border} paddingX={2}>
 84→        <Box gap={1}>
 85→          {depth > 0 ? <Text dimColor>{IconSelected2.repeat(depth)} </Text> : null}
 86→          <Text bold color={roleColor(message.role)}>
 87→            {roleIcon(message.role)}{" "}
 88→            {message.role === "claude" ? "Claude" : message.role === "user" ? "User" : "System"}
 89→          </Text>
 90→          {message.subagent_label ? (
 91→            <Text color={colors.itemAgent}>[{message.subagent_label}]</Text>
 92→          ) : null}
 93→          <StatsBar stats={stats} />
 94→          {ongoing ? <BrailleSpinner /> : null}
 95→        </Box>
 96→        {items.length > 0 ? (
 97→          <Text dimColor wrap="truncate">
 98→            {truncate(message.content, contentWidth - 8)}
 99→          </Text>
100→        ) : null}
101→      </Box>
102→
103→      {/* Full content when no items */}
104→      {items.length === 0 ? (
105→        <Box paddingX={2} flexDirection="column">
106→          <Text wrap="wrap">{message.content}</Text>
107→        </Box>
108→      ) : (
109→        <Box flexDirection="column" paddingTop={1}>
110→          {visible.map((item, i) => {
111→            const idx = start + i;
112→            const isSelected = idx === selectedItem;
113→            const isExpanded = expandedItems.has(idx);
114→            const clr = itemBorderColor(item, isSelected);
115→            const hasAgent = item.subagent_messages.length > 0;
116→            const teamClr = item.team_color ? getTeamColor(item.team_color) : undefined;
117→            const accentClr = hasAgent && teamClr ? teamClr : clr;
118→
119→            // Go TUI format: {cursor} {icon} {name:<maxNameLen} {summary}  {tokens:>9} {duration:<5}
120→            const summaryMaxLen = contentWidth - maxNameLen - 30; // leave room for tokens + duration
121→
122→            return (
123→              <Box
124→                key={`${item.item_type}-${idx}-${item.tool_name || item.agent_id || ""}`}
125→                flexDirection="row"
126→              >
127→                {/* Left accent — double bar for subagents with messages */}
128→                <Text color={accentClr}>{hasAgent ? IconBarDouble : IconBarSingle}</Text>
129→                <Box flexDirection="column" flexGrow={1} paddingLeft={1}>
130→                  {/* Item header row — Go TUI aligned format */}
131→                  <Box>
132→                    {/* Cursor + icon + name (fixed width) */}
133→                    <Text bold={isSelected} inverse={isSelected} color={accentClr}>
134→                      {isExpanded ? IconExpanded : IconCollapsed} {getItemIcon(item)}{" "}
135→                      {getItemName(item).padEnd(maxNameLen)}
136→                    </Text>
137→                    {/* Summary — "- " separator matches Go TUI */}
138→                    {getItemSummary(item) ? (
139→                      <Text dimColor> - {truncate(getItemSummary(item), summaryMaxLen)}</Text>
140→                    ) : null}
141→                    {/* Spacer */}
142→                    <Box flexGrow={1} />
143→                    {/* Right-aligned: tokens + duration */}
144→                    {item.token_count > 0 ? (
145→                      <Text dimColor>{formatTokens(item.token_count).padStart(9)}</Text>
146→                    ) : null}
147→                    {item.duration_ms > 0 ? (
148→                      <Text dimColor> {formatDuration(item.duration_ms).padEnd(5)}</Text>
149→                    ) : null}
150→                    {item.subagent_ongoing ? <OngoingDot /> : null}
151→                    {hasAgent ? (
152→                      <Text color={teamClr || colors.itemAgent} dimColor>
153→                        {" "}
154→                        [{item.subagent_messages.length} msg]
155→                      </Text>
156→                    ) : null}
157→                  </Box>
158→
159→                  {/* Expanded body */}
160→                  {isExpanded && <DetailItemBody item={item} cols={contentWidth} />}
161→                </Box>
162→              </Box>
163→            );
164→          })}
165→        </Box>
166→      )}
167→    </Box>
168→  );
169→}
170→
171→/**
172→ * Expanded item body — matches Go TUI: 4-space indent, plain text, no bordered boxes.
173→ * ToolCall Input/Result separated by dashed line. Section headers are bold+dim labels.
174→ */
175→const MAX_BODY_LINES = 40;
176→// Left accent bar(1) + paddingLeft(1) + body indent(4) = 6
177→const BODY_INDENT_OVERHEAD = 6;
178→
179→function DetailItemBody({ item, cols }: { item: DisplayItem; cols: number }) {
180→  const wrapWidth = Math.max(cols - BODY_INDENT_OVERHEAD - 4, 20); // matches Go: max(width-8, 20)
181→  const clamp = (text: string) => clampLines(limitLines(text, MAX_BODY_LINES), wrapWidth);
182→  const hrule = IconHRule.repeat(Math.min(wrapWidth, 40));
183→
184→  switch (item.item_type) {
185→    case "Thinking":
186→      return (
187→        <Box flexDirection="column" paddingLeft={4}>
188→          <Text color={colors.itemThinking} wrap="truncate">
189→            {clamp(item.text || "Thinking content is not recorded in session logs.")}
190→          </Text>
191→        </Box>
192→      );
193→    case "Output":
194→      return (
195→        <Box flexDirection="column" paddingLeft={4}>
196→          <Text wrap="truncate">{clamp(item.text)}</Text>
197→        </Box>
198→      );
199→    case "ToolCall":
200→      return (
201→        <Box flexDirection="column" paddingLeft={4}>
202→          {item.tool_input && (
203→            <Box flexDirection="column">
204→              <Text bold color={colors.textSecondary}>
205→                Input:
206→              </Text>
207→              <Text dimColor wrap="truncate">
208→                {clamp(formatJson(item.tool_input))}
209→              </Text>
210→            </Box>
211→          )}
212→          {item.tool_input && item.tool_result && <Text color={colors.textMuted}>{hrule}</Text>}
213→          {item.tool_result && (
214→            <Box flexDirection="column">
215→              <Text bold color={item.tool_error ? colors.error : colors.textSecondary}>
216→                {item.tool_error ? "Error:" : "Result:"}
217→              </Text>
218→              <Text color={item.tool_error ? colors.error : undefined} wrap="truncate">
219→                {clamp(item.tool_result)}
220→              </Text>
221→            </Box>
222→          )}
223→        </Box>
224→      );
225→    case "Subagent":
226→      return (
227→        <Box flexDirection="column" paddingLeft={4}>
228→          {item.agent_id && (
229→            <Box gap={1}>
230→              <Text color={colors.textMuted} bold>
231→                id:
232→              </Text>
233→              <Text dimColor>{item.agent_id}</Text>
234→            </Box>
235→          )}
236→          {item.subagent_desc && (
237→            <Box gap={1}>
238→              <Text color={colors.textMuted} bold>
239→                description:
240→              </Text>
241→              <Text wrap="truncate">{truncate(item.subagent_desc, wrapWidth - 15)}</Text>
242→            </Box>
243→          )}
244→          {item.subagent_prompt && (
245→            <Box flexDirection="column">
246→              <Text color={colors.textMuted} bold>
247→                prompt:
248→              </Text>
249→              <Text dimColor wrap="truncate">
250→                {clamp(item.subagent_prompt)}
251→              </Text>
252→            </Box>
253→          )}
254→          {item.text && (
255→            <Box flexDirection="column">
256→              <Text color={colors.textMuted}>{hrule}</Text>
257→              <Text bold color={colors.textSecondary}>
258→                Result:
259→              </Text>
260→              <Text wrap="truncate">{clamp(item.text)}</Text>
261→            </Box>
262→          )}
263→        </Box>
264→      );
265→    case "TeammateMessage":
266→      return (
267→        <Box flexDirection="column" paddingLeft={4}>
268→          <Text wrap="truncate">{clamp(item.text)}</Text>
269→        </Box>
270→      );
271→    case "HookEvent":
272→      return (
273→        <Box flexDirection="column" paddingLeft={4}>
274→          <Box gap={1}>
275→            <Text color={colors.textMuted} bold>
276→              hook:
277→            </Text>
278→            <Text>
279→              {item.hook_event}: {item.hook_name}
280→            </Text>
281→          </Box>
282→          {item.hook_command && (
283→            <Box gap={1}>
284→              <Text color={colors.textMuted} bold>
285→                cmd:
286→              </Text>
287→              <Text dimColor>{item.hook_command}</Text>
288→            </Box>
289→          )}
290→        </Box>
291→      );
292→    default:
293→      return (
294→        <Box flexDirection="column" paddingLeft={4}>
295→          <Text wrap="truncate">{clamp(item.text)}</Text>
296→        </Box>
297→      );
298→  }
299→}
