 1→import type { DisplayItem } from "../api.js";
 2→import { truncate } from "./format.js";
 3→import {
 4→  IconThinking,
 5→  IconOutput,
 6→  IconTool,
 7→  IconSubagent,
 8→  IconTeammate,
 9→  IconHook,
10→  IconDot,
11→} from "./icons.js";
12→
13→/** Nerd Font icon for a DisplayItem type (matches Go TUI). */
14→export function getItemIcon(item: DisplayItem): string {
15→  switch (item.item_type) {
16→    case "Thinking":
17→      return IconThinking;
18→    case "Output":
19→      return IconOutput;
20→    case "ToolCall":
21→      return IconTool;
22→    case "Subagent":
23→      return IconSubagent;
24→    case "TeammateMessage":
25→      return IconTeammate;
26→    case "HookEvent":
27→      return IconHook;
28→    default:
29→      return IconDot;
30→  }
31→}
32→
33→/** Display name for a DisplayItem. */
34→export function getItemName(item: DisplayItem): string {
35→  switch (item.item_type) {
36→    case "Thinking":
37→      return "Thinking";
38→    case "Output":
39→      return "Output";
40→    case "ToolCall":
41→      return item.tool_name || "Tool";
42→    case "Subagent":
43→      return item.subagent_type || "Subagent";
44→    case "TeammateMessage":
45→      return item.team_member_name || "Teammate";
46→    case "HookEvent":
47→      return item.hook_event || "Hook";
48→    default:
49→      return item.item_type;
50→  }
51→}
52→
53→/** Short summary for a DisplayItem. */
54→export function getItemSummary(item: DisplayItem): string {
55→  switch (item.item_type) {
56→    case "ToolCall":
57→      return item.tool_summary || "";
58→    case "Subagent":
59→      return item.subagent_desc || "";
60→    case "TeammateMessage":
61→      return item.text ? item.text.slice(0, 100) : "";
62→    case "Thinking":
63→      return item.text
64→        ? item.text.slice(0, 80) + (item.text.length > 80 ? "…" : "")
65→        : "Content not recorded";
66→    case "Output":
67→      return item.text ? item.text.slice(0, 80) + (item.text.length > 80 ? "…" : "") : "";
68→    case "HookEvent":
69→      return item.hook_name
70→        ? `${item.hook_name}${item.hook_command ? ": " + truncate(item.hook_command, 60) : ""}`
71→        : item.hook_command
72→          ? truncate(item.hook_command, 80)
73→          : "";
74→    default:
75→      return "";
76→  }
77→}
