  1→import { Box, Text } from "ink";
  2→import type { DisplayMessage } from "../api.js";
  3→import { truncate, roleColor, roleIcon, shortModel, modelColor, firstLine } from "../lib/format.js";
  4→import { colors, getRoleBorderColor, getItemColor, getTeamColor } from "../lib/theme.js";
  5→import { getItemIcon, getItemName } from "../lib/items.js";
  6→import { StatsBar, statsFromMessage } from "./StatsBar.js";
  7→import { BrailleSpinner } from "./OngoingDots.js";
  8→import { stableWindow } from "../lib/window.js";
  9→import {
 10→  IconSelected2,
 11→  IconBarSingle,
 12→  IconBarDouble,
 13→  IconOngoingDot,
 14→  IconHRule,
 15→  IconDot,
 16→} from "../lib/icons.js";
 17→
 18→/** Max content width — matches Go TUI's maxContentWidth. */
 19→const MAX_CONTENT_WIDTH = 160;
 20→
 21→interface MessageListProps {
 22→  messages: DisplayMessage[];
 23→  selectedIndex: number;
 24→  expandedSet: Set<number>;
 25→  ongoing: boolean;
 26→}
 27→
 28→export function MessageList({ messages, selectedIndex, expandedSet, ongoing }: MessageListProps) {
 29→  const cols = process.stdout.columns || 80;
 30→  const contentWidth = Math.min(cols, MAX_CONTENT_WIDTH);
 31→  // Each message card: border top(1) + header(1) + body(1) + stats(1) + border bottom(1) = 5 lines
 32→  // Account for InfoBar(3) + KeybindBar(3) = 6 lines of chrome
 33→  const rows = process.stdout.rows || 24;
 34→  const windowSize = Math.max(3, Math.floor((rows - 6) / 5));
 35→  const { start, end } = stableWindow("messages", selectedIndex, messages.length, windowSize);
 36→  const visible = messages.slice(start, end);
 37→
 38→  if (messages.length === 0) {
 39→    return (
 40→      <Box paddingX={1}>
 41→        <Text dimColor>No messages loaded</Text>
 42→      </Box>
 43→    );
 44→  }
 45→
 46→  return (
 47→    <Box flexDirection="column">
 48→      {visible.map((msg, i) => {
 49→        const idx = start + i;
 50→        const isSelected = idx === selectedIndex;
 51→        const isExpanded = expandedSet.has(idx);
 52→        const isLast = idx === messages.length - 1;
 53→        const stats = statsFromMessage(msg);
 54→        const model = msg.model ? shortModel(msg.model) : "";
 55→
 56→        // System messages — centered dashed separator (matches Go TUI)
 57→        if (msg.role === "compact") {
 58→          return (
 59→            <Box key={`compact-${idx}`} paddingX={1} justifyContent="center">
 60→              <Text dimColor>
 61→                {IconHRule.repeat(6)} {msg.content} {IconHRule.repeat(6)}
 62→              </Text>
 63→            </Box>
 64→          );
 65→        }
 66→
 67→        if (msg.role === "system") {
 68→          const sysText = `${IconHRule}${IconHRule} ${roleIcon("system")} System ${IconDot} ${truncate(msg.content, contentWidth - 20)} ${IconHRule}${IconHRule}`;
 69→          return (
 70→            <Box key={`sys-${idx}`} justifyContent="center" paddingX={2}>
 71→              <Text color={colors.textMuted}>{sysText}</Text>
 72→            </Box>
 73→          );
 74→        }
 75→
 76→        const bodyWidth = contentWidth - 8; // border(2) + paddingX(4) + accent bar(2)
 77→        const contentPreview = isExpanded
 78→          ? msg.content
 79→          : truncate(firstLine(msg.content), bodyWidth);
 80→        const borderClr = isSelected ? colors.accent : getRoleBorderColor(msg.role, msg.is_error);
 81→
 82→        return (
 83→          <Box
 84→            key={`msg-${idx}-${msg.role}`}
 85→            flexDirection="column"
 86→            borderStyle="round"
 87→            borderColor={borderClr}
 88→            paddingX={2}
 89→          >
 90→            {/* Header: role icon + name + model + stats */}
 91→            <Box gap={1}>
 92→              <Text
 93→                bold
 94→                inverse={isSelected}
 95→                color={isSelected ? colors.accent : roleColor(msg.role)}
 96→              >
 97→                {isSelected ? `${IconSelected2} ` : "  "}
 98→                {roleIcon(msg.role)} {msg.role === "claude" ? "Claude" : "User"}
 99→              </Text>
100→              {model ? (
101→                <Text color={modelColor(msg.model)} dimColor={!isSelected}>
102→                  {model}
103→                </Text>
104→              ) : null}
105→              {msg.subagent_label ? (
106→                <Text color={colors.itemAgent} dimColor>
107→                  [{msg.subagent_label}]
108→                </Text>
109→              ) : null}
110→              {isLast && ongoing ? <BrailleSpinner /> : null}
111→              {isSelected ? (
112→                <Text dimColor>
113→                  [{idx + 1}/{messages.length}]
114→                </Text>
115→              ) : null}
116→            </Box>
117→
118→            {/* Body content — indented 2 spaces under header (matches Go TUI) */}
119→            <Box paddingLeft={2}>
120→              <Text dimColor={!isSelected} wrap={isExpanded ? "wrap" : "truncate"}>
121→                {contentPreview}
122→              </Text>
123→            </Box>
124→
125→            {/* Stats row — aligned with body content */}
126→            <Box paddingLeft={2}>
127→              <StatsBar stats={stats} />
128→            </Box>
129→
130→            {/* Expanded items tree */}
131→            {isExpanded && msg.items.length > 0 && (
132→              <Box flexDirection="column" paddingLeft={2} marginTop={0}>
133→                {msg.items.map((item) => (
134→                  <Box
135→                    key={`${idx}-${item.item_type}-${item.tool_name || item.agent_id || ""}-${item.duration_ms}`}
136→                    flexDirection="row"
137→                  >
138→                    <Text color={item.team_color ? getTeamColor(item.team_color) : colors.border}>
139→                      {item.subagent_messages.length > 0 ? IconBarDouble : IconBarSingle}
140→                    </Text>
141→                    <Box paddingLeft={1}>
142→                      <Text
143→                        color={
144→                          item.team_color
145→                            ? getTeamColor(item.team_color)
146→                            : getItemColor(item.item_type, !!item.tool_error)
147→                        }
148→                      >
149→                        {getItemIcon(item)} {getItemName(item)}
150→                        {item.tool_summary
151→                          ? ` — ${truncate(item.tool_summary, bodyWidth - 20)}`
152→                          : item.subagent_desc
153→                            ? ` — ${truncate(item.subagent_desc, bodyWidth - 20)}`
154→                            : item.text && item.item_type !== "ToolCall"
155→                              ? ` ${truncate(item.text, bodyWidth - 20)}`
156→                              : ""}
157→                        {item.subagent_ongoing ? ` ${IconOngoingDot}` : ""}
158→                        {item.subagent_messages.length > 0
159→                          ? ` [${item.subagent_messages.length} msg]`
160→                          : ""}
161→                      </Text>
162→                    </Box>
163→                  </Box>
164→                ))}
165→              </Box>
166→            )}
167→          </Box>
168→        );
169→      })}
170→    </Box>
171→  );
172→}
