  1→import type { ReactNode } from "react";
  2→import { Box, Text } from "ink";
  3→import type { DisplayMessage } from "../api.js";
  4→import { formatTokens, formatDuration } from "../lib/format.js";
  5→import { colors } from "../lib/theme.js";
  6→import { IconThinking, IconTool, IconOutput, IconSubagent, IconSpawn } from "../lib/icons.js";
  7→
  8→export interface Stats {
  9→  tokens: number;
 10→  toolCount: number;
 11→  thinkingCount: number;
 12→  outputCount: number;
 13→  durationMs: number;
 14→  agentCount: number;
 15→  spawnCount: number;
 16→}
 17→
 18→export function statsFromMessage(msg: DisplayMessage): Stats {
 19→  const agentCount = msg.items.filter(
 20→    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 21→  ).length;
 22→  return {
 23→    tokens: msg.tokens_raw,
 24→    toolCount: msg.tool_call_count,
 25→    thinkingCount: msg.thinking_count,
 26→    outputCount: msg.output_count,
 27→    durationMs: msg.duration_ms,
 28→    agentCount,
 29→    spawnCount: msg.teammate_spawns,
 30→  };
 31→}
 32→
 33→function hasAny(s: Stats): boolean {
 34→  return (
 35→    s.tokens > 0 ||
 36→    s.toolCount > 0 ||
 37→    s.thinkingCount > 0 ||
 38→    s.outputCount > 0 ||
 39→    s.durationMs > 0 ||
 40→    s.agentCount > 0 ||
 41→    s.spawnCount > 0
 42→  );
 43→}
 44→
 45→/** Middle dot separator for stats. */
 46→function Dot() {
 47→  return <Text color={colors.textMuted}> · </Text>;
 48→}
 49→
 50→export function StatsBar({ stats }: { stats: Stats }) {
 51→  if (!hasAny(stats)) return null;
 52→
 53→  // Build parts array, then join with dots (matches Go TUI stat row)
 54→  const parts: { id: string; node: ReactNode }[] = [];
 55→
 56→  if (stats.thinkingCount > 0) {
 57→    parts.push({
 58→      id: "think",
 59→      node: (
 60→        <Text dimColor color={colors.itemThinking}>
 61→          {IconThinking} {stats.thinkingCount}
 62→        </Text>
 63→      ),
 64→    });
 65→  }
 66→  if (stats.toolCount > 0) {
 67→    parts.push({
 68→      id: "tool",
 69→      node: (
 70→        <Text dimColor color={colors.itemTool}>
 71→          {IconTool} {stats.toolCount}
 72→        </Text>
 73→      ),
 74→    });
 75→  }
 76→  if (stats.outputCount > 0) {
 77→    parts.push({
 78→      id: "out",
 79→      node: (
 80→        <Text dimColor>
 81→          {IconOutput} {stats.outputCount}
 82→        </Text>
 83→      ),
 84→    });
 85→  }
 86→  if (stats.agentCount > 0) {
 87→    parts.push({
 88→      id: "agent",
 89→      node: (
 90→        <Text dimColor color={colors.itemAgent}>
 91→          {IconSubagent} {stats.agentCount}
 92→        </Text>
 93→      ),
 94→    });
 95→  }
 96→  if (stats.spawnCount > 0) {
 97→    parts.push({
 98→      id: "spawn",
 99→      node: (
100→        <Text dimColor>
101→          {IconSpawn} {stats.spawnCount}
102→        </Text>
103→      ),
104→    });
105→  }
106→  if (stats.tokens > 0) {
107→    parts.push({
108→      id: "tok",
109→      node: (
110→        <Text dimColor color={stats.tokens > 150000 ? colors.tokenHigh : undefined}>
111→          {formatTokens(stats.tokens)}
112→        </Text>
113→      ),
114→    });
115→  }
116→  if (stats.durationMs > 0) {
117→    parts.push({
118→      id: "dur",
119→      node: <Text dimColor>{formatDuration(stats.durationMs)}</Text>,
120→    });
121→  }
122→
123→  return (
124→    <Box>
125→      {parts.map((part, idx) => (
126→        <Box key={part.id}>
127→          {idx > 0 && <Dot />}
128→          {part.node}
129→        </Box>
130→      ))}
131→    </Box>
132→  );
133→}
