 86→/// Estimate output tokens from assistant message content character count.
 87→/// Returns 0 if estimation is not possible.
 88→pub fn estimate_output_from_content(raw: &serde_json::Value) -> i64 {
 89→    let content = match raw.get("message").and_then(|m| m.get("content")) {
 90→        Some(c) => c,
 91→        None => return 0,
 92→    };
 93→    let arr = match content.as_array() {
 94→        Some(a) => a,
 95→        None => return 0,
 96→    };
 97→
 98→    let mut total_chars: i64 = 0;
 99→    for block in arr {
100→        let btype = block.get("type").and_then(|v| v.as_str()).unwrap_or("");
101→        match btype {
102→            "text" => {
103→                if let Some(t) = block.get("text").and_then(|v| v.as_str()) {
104→                    total_chars += t.len() as i64;
105→                }
106→            }
107→            "thinking" => {
108→                if let Some(t) = block.get("thinking").and_then(|v| v.as_str()) {
109→                    total_chars += t.len() as i64;
110→                }
111→            }
112→            "tool_use" => {
113→                // tool_use name + JSON input serialization
114→                total_chars += 20; // name overhead
115→                if let Some(input) = block.get("input") {
116→                    total_chars += input.to_string().len() as i64;
117→                }
118→            }
119→            _ => {}
120→        }
121→    }
122→    // Rough estimate: ~4 characters per token for English text/code.
123→    total_chars / 4
124→}
125→
126→/// Compute cost in USD from a set of token snapshots, pricing each by its model.
127→pub fn estimate_cost_from_snapshots(
128→    request_tokens: &std::collections::HashMap<String, TokenSnapshot>,
129→    fallback: &TokenSnapshot,
130→) -> f64 {
131→    let mut cost = 0.0;
132→
133→    // Fallback tokens (no requestId) — use fallback.model for pricing.
134→    if fallback.input + fallback.output + fallback.cache_read + fallback.cache_create > 0 {
135→        let p = pricing_for_model(&fallback.model);
136→        cost += (fallback.input as f64 * p.input
137→            + fallback.output as f64 * p.output
138→            + fallback.cache_read as f64 * p.cache_read
139→            + fallback.cache_create as f64 * p.cache_write)
140→            / 1_000_000.0;
141→    }
142→
143→    for snap in request_tokens.values() {
144→        let p = pricing_for_model(&snap.model);
145→        cost += (snap.input as f64 * p.input
146→            + snap.output as f64 * p.output
147→            + snap.cache_read as f64 * p.cache_read
148→            + snap.cache_create as f64 * p.cache_write)
149→            / 1_000_000.0;
150→    }
151→    cost
152→}
