333→fn is_warmup_agent(path: &str) -> bool {
334→    let f = match fs::File::open(path) {
335→        Ok(f) => f,
336→        Err(_) => return false,
337→    };
338→    let reader = BufReader::new(f);
339→    for line_result in reader.lines() {
340→        let line = match line_result {
341→            Ok(l) => l,
342→            Err(_) => break,
343→        };
344→        let raw: serde_json::Value = match serde_json::from_str(&line) {
345→            Ok(v) => v,
346→            Err(_) => continue,
347→        };
348→        let entry_type = raw.get("type").and_then(|v| v.as_str()).unwrap_or("");
349→        if entry_type != "user" {
350→            continue;
351→        }
352→        let content = raw
353→            .get("message")
354→            .and_then(|m| m.get("content"))
355→            .and_then(|c| c.as_str())
356→            .unwrap_or("");
357→        return content == "Warmup";
358→    }
359→    false
360→}
