437→/// Link subagents to parent Task tool calls. Returns toolID -> color map.
438→pub fn link_subagents(
439→    processes: &mut [SubagentProcess],
440→    parent_chunks: &[Chunk],
441→    parent_session_path: &str,
442→) -> HashMap<String, String> {
443→    let mut links = scan_agent_links(parent_session_path);
444→
445→    // Also scan subagent files for skill_progress entries (Skill forked execution).
446→    for proc in processes.iter() {
447→        let skill_links = scan_skill_progress_links(&proc.file_path);
448→        for (agent_id, tool_id) in skill_links {
449→            links.agent_to_tool_id.entry(agent_id).or_insert(tool_id);
450→        }
451→    }
452→
453→    if processes.is_empty() {
454→        return links.tool_id_to_color;
455→    }
456→
457→    // Collect tool IDs that have known agent links (for ToolCall items like Skill).
458→    let linked_tool_ids: HashSet<&str> = links
459→        .agent_to_tool_id
460→        .values()
461→        .map(|s| s.as_str())
462→        .collect();
463→
464→    // Collect all Subagent DisplayItems + ToolCall items that have agent links.
465→    let mut task_items: Vec<&DisplayItem> = Vec::new();
466→    for c in parent_chunks {
467→        if c.chunk_type != ChunkType::AI {
468→            continue;
469→        }
470→        for item in &c.items {
471→            if item.item_type == DisplayItemType::Subagent
472→                || (item.item_type == DisplayItemType::ToolCall
473→                    && linked_tool_ids.contains(item.tool_id.as_str()))
474→            {
475→                task_items.push(item);
476→            }
477→        }
478→    }
479→
480→    let tool_id_to_task: HashMap<String, &DisplayItem> = task_items
481→        .iter()
482→        .map(|it| (it.tool_id.clone(), *it))
483→        .collect();
484→
485→    let mut matched_procs: HashMap<String, bool> = HashMap::new();
486→    let mut matched_tools: HashMap<String, bool> = HashMap::new();
487→
488→    // Phase 1: Result-based matching.
489→    for proc in processes.iter_mut() {
490→        if let Some(tool_id) = links.agent_to_tool_id.get(&proc.id) {
491→            if let Some(item) = tool_id_to_task.get(tool_id) {
492→                proc.parent_task_id = item.tool_id.clone();
493→                proc.description = item.subagent_desc.clone();
494→                proc.subagent_type = item.subagent_type.clone();
495→                matched_procs.insert(proc.id.clone(), true);
496→                matched_tools.insert(tool_id.clone(), true);
497→            } else {
498→                // Tool ID not in parent chunks (e.g. Skill inside a subagent).
499→                // Set parent_task_id anyway so convert_display_items can link
500→                // when processing the subagent's nested chunks.
501→                proc.parent_task_id = tool_id.clone();
502→                matched_procs.insert(proc.id.clone(), true);
503→            }
504→        }
505→    }
506→
507→    // Phase 2: Team member matching by description.
508→    let team_task_items: Vec<&&DisplayItem> = task_items
509→        .iter()
510→        .filter(|it| !matched_tools.contains_key(&it.tool_id) && is_team_task(it))
511→        .collect();
512→
513→    for item in &team_task_items {
514→        let mut best_idx: Option<usize> = None;
515→        for (i, proc) in processes.iter().enumerate() {
516→            if matched_procs.contains_key(&proc.id) {
517→                continue;
518→            }
519→            if proc.team_summary.is_empty() || proc.team_summary != item.subagent_desc {
520→                continue;
521→            }
522→            if best_idx.is_none()
523→                || processes[i].start_time < processes[best_idx.unwrap()].start_time
524→            {
525→                best_idx = Some(i);
526→            }
527→        }
528→        if let Some(idx) = best_idx {
529→            processes[idx].parent_task_id = item.tool_id.clone();
530→            processes[idx].description = item.subagent_desc.clone();
531→            processes[idx].subagent_type = item.subagent_type.clone();
532→            matched_procs.insert(processes[idx].id.clone(), true);
533→            matched_tools.insert(item.tool_id.clone(), true);
534→        }
535→    }
536→
537→    // Phase 3: Positional fallback.
538→    let unmatched_procs: Vec<usize> = processes
539→        .iter()
540→        .enumerate()
541→        .filter(|(_, p)| !matched_procs.contains_key(&p.id))
542→        .map(|(i, _)| i)
543→        .collect();
544→    let unmatched_tasks: Vec<&&DisplayItem> = task_items
545→        .iter()
546→        .filter(|it| !matched_tools.contains_key(&it.tool_id) && !is_team_task(it))
547→        .collect();
548→
549→    for (i, task) in unmatched_tasks.iter().enumerate() {
550→        if i >= unmatched_procs.len() {
551→            break;
552→        }
553→        let idx = unmatched_procs[i];
554→        processes[idx].parent_task_id = task.tool_id.clone();
555→        processes[idx].description = task.subagent_desc.clone();
556→        processes[idx].subagent_type = task.subagent_type.clone();
557→    }
558→
559→    // Phase 4: Nested enrichment — search all processes' chunks for task items
560→    // to fill in description/type for processes that Phase 1 linked by tool_id
561→    // but couldn't find in the parent session's chunks. This handles cases where
562→    // a subagent spawns further subagents via Skill/Agent.
563→    let needs_enrichment = processes
564→        .iter()
565→        .any(|p| !p.parent_task_id.is_empty() && p.description.is_empty());
566→    if needs_enrichment {
567→        // Collect task items from all processes' chunks.
568→        let mut nested_task_items: Vec<DisplayItem> = Vec::new();
569→        for proc in processes.iter() {
570→            for c in &proc.chunks {
571→                if c.chunk_type != ChunkType::AI {
572→                    continue;
573→                }
574→                for item in &c.items {
575→                    if item.item_type == DisplayItemType::Subagent
576→                        || (item.item_type == DisplayItemType::ToolCall
577→                            && linked_tool_ids.contains(item.tool_id.as_str()))
578→                    {
579→                        nested_task_items.push(item.clone());
580→                    }
581→                }
582→            }
583→        }
584→        let nested_task_map: HashMap<String, &DisplayItem> = nested_task_items
585→            .iter()
586→            .map(|it| (it.tool_id.clone(), it))
587→            .collect();
588→        for proc in processes.iter_mut() {
589→            if proc.description.is_empty() {
590→                if let Some(item) = nested_task_map.get(&proc.parent_task_id) {
591→                    // Use subagent_desc if available, otherwise fall back to tool_summary.
592→                    proc.description = if !item.subagent_desc.is_empty() {
593→                        item.subagent_desc.clone()
594→                    } else {
595→                        item.tool_summary.clone()
596→                    };
597→                    if proc.subagent_type.is_empty() {
598→                        proc.subagent_type = item.subagent_type.clone();
599→                    }
600→                }
601→            }
602→        }
603→    }
604→
605→    // Populate teammate color from toolUseResult data.
606→    for proc in processes.iter_mut() {
607→        if proc.teammate_color.is_empty() && !proc.parent_task_id.is_empty() {
608→            if let Some(color) = links.tool_id_to_color.get(&proc.parent_task_id) {
609→                proc.teammate_color = color.clone();
610→            }
611→        }
612→    }
613→
614→    // Remap IDs for team workers.
615→    for proc in processes.iter_mut() {
616→        if proc.parent_task_id.is_empty() {
617→            continue;
618→        }
619→        if let Some(item) = tool_id_to_task.get(&proc.parent_task_id) {
620→            if is_team_task(item) {
621→                if let Some(Value::Object(map)) = &item.tool_input {
622→                    let team_name = map.get("team_name").and_then(|v| v.as_str()).unwrap_or("");
623→                    let agent_name = map.get("name").and_then(|v| v.as_str()).unwrap_or("");
624→                    if !team_name.is_empty() && !agent_name.is_empty() {
625→                        proc.id = format!("{agent_name}@{team_name}");
626→                    }
627→                }
628→            }
629→        }
630→    }
631→
632→    links.tool_id_to_color
633→}
