635→/// Inject synthetic Subagent DisplayItems for processes that remain unlinked
636→/// (no parent_task_id) after all linking phases. Appends them to the last AI
637→/// chunk, or creates a new AI chunk if none exists.
638→pub fn inject_orphan_subagents(chunks: &mut Vec<Chunk>, processes: &mut [SubagentProcess]) {
639→    let mut orphan_indices: Vec<usize> = processes
640→        .iter()
641→        .enumerate()
642→        .filter(|(_, p)| p.parent_task_id.is_empty() && !p.chunks.is_empty())
643→        .map(|(i, _)| i)
644→        .collect();
645→
646→    if orphan_indices.is_empty() {
647→        return;
648→    }
649→
650→    // Sort orphans oldest-first (ascending start_time).
651→    orphan_indices.sort_by(|&a, &b| processes[a].start_time.cmp(&processes[b].start_time));
652→
653→    // Find or create last AI chunk.
654→    let ai_idx = chunks.iter().rposition(|c| c.chunk_type == ChunkType::AI);
655→
656→    let idx = match ai_idx {
657→        Some(i) => i,
658→        None => {
659→            // No AI chunk — create a synthetic one.
660→            chunks.push(Chunk {
661→                chunk_type: ChunkType::AI,
662→                timestamp: processes[orphan_indices[0]].start_time,
663→                ..Default::default()
664→            });
665→            chunks.len() - 1
666→        }
667→    };
668→
669→    for &oi in &orphan_indices {
670→        let synthetic_tool_id = format!("orphan-{}", processes[oi].id);
671→        // Set parent_task_id so convert_display_items can link via proc_by_task_id.
672→        processes[oi].parent_task_id = synthetic_tool_id.clone();
673→
674→        chunks[idx].items.push(DisplayItem {
675→            item_type: DisplayItemType::Subagent,
676→            tool_name: "Agent".to_string(),
677→            tool_id: synthetic_tool_id,
678→            subagent_type: processes[oi].subagent_type.clone(),
679→            subagent_desc: processes[oi].description.clone(),
680→            is_orphan: true,
681→            duration_ms: processes[oi].duration_ms,
682→            ..Default::default()
683→        });
684→    }
685→}
