687→struct AgentLinkData {
688→    agent_to_tool_id: HashMap<String, String>,
689→    tool_id_to_color: HashMap<String, String>,
690→}
691→
692→fn scan_agent_links(session_path: &str) -> AgentLinkData {
693→    let mut data = AgentLinkData {
694→        agent_to_tool_id: HashMap::new(),
695→        tool_id_to_color: HashMap::new(),
696→    };
697→
698→    let f = match fs::File::open(session_path) {
699→        Ok(f) => f,

 700→        Err(_) => return data,
 701→    };
 702→    let reader = BufReader::new(f);
 703→
 704→    for line_result in reader.lines() {
 705→        let line = match line_result {
 706→            Ok(l) => l,
 707→            Err(_) => break,
 708→        };
 709→        let entry = match parse_entry(line.as_bytes()) {
 710→            Some(e) => e,
 711→            None => continue,
 712→        };
 713→        let result_map = match entry.tool_use_result_map() {
 714→            Some(m) => m,
 715→            None => continue,
 716→        };
 717→
 718→        let agent_id = result_map
 719→            .get("agentId")
 720→            .or_else(|| result_map.get("agent_id"))
 721→            .and_then(|v| v.as_str())
 722→            .unwrap_or("")
 723→            .to_string();
 724→        if agent_id.is_empty() {
 725→            continue;
 726→        }
 727→
 728→        let mut tool_use_id = entry.source_tool_use_id.clone();
 729→        if tool_use_id.is_empty() {
 730→            tool_use_id = extract_first_tool_result_id(&entry);
 731→        }
 732→        if tool_use_id.is_empty() {
 733→            continue;
 734→        }
 735→
 736→        data.agent_to_tool_id.insert(agent_id, tool_use_id.clone());
 737→
 738→        if let Some(color) = result_map.get("color").and_then(|v| v.as_str()) {
 739→            if !color.is_empty() {
 740→                data.tool_id_to_color.insert(tool_use_id, color.to_string());
 741→            }
 742→        }
 743→    }
 744→
 745→    data
 746→}
 747→
 748→/// Scan a JSONL file for skill_progress entries to find Skill → agent links.
 749→/// Returns agentId → tool_use_id mapping.
 750→fn scan_skill_progress_links(file_path: &str) -> HashMap<String, String> {
 751→    let mut result: HashMap<String, String> = HashMap::new();
 752→
 753→    let f = match fs::File::open(file_path) {
 754→        Ok(f) => f,
 755→        Err(_) => return result,
 756→    };
 757→    let reader = BufReader::new(f);
 758→
 759→    for line_result in reader.lines() {
 760→        let line = match line_result {
 761→            Ok(l) => l,
 762→            Err(_) => break,
 763→        };
 764→
 765→        if !line.contains("skill_progress") {
 766→            continue;
 767→        }
 768→
 769→        if let Ok(v) = serde_json::from_str::<Value>(&line) {
 770→            let data_type = v
 771→                .pointer("/data/type")
 772→                .and_then(|v| v.as_str())
 773→                .unwrap_or("");
 774→            if data_type != "skill_progress" {
 775→                continue;
 776→            }
 777→            let agent_id = v
 778→                .pointer("/data/agentId")
 779→                .and_then(|v| v.as_str())
 780→                .unwrap_or("");
 781→            let parent_tool_id = v
 782→                .get("parentToolUseID")
 783→                .and_then(|v| v.as_str())
 784→                .unwrap_or("");
 785→            if !agent_id.is_empty() && !parent_tool_id.is_empty() && !result.contains_key(agent_id)
 786→            {
 787→                result.insert(agent_id.to_string(), parent_tool_id.to_string());
 788→            }
 789→        }
 790→    }
 791→
 792→    result
 793→}
 794→
 795→fn extract_first_tool_result_id(entry: &super::entry::Entry) -> String {
 796→    if let Some(Value::Array(blocks)) = &entry.message.content {
 797→        for b in blocks {
 798→            let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
 799→            if bt == "tool_result" {
 800→                if let Some(id) = b.get("tool_use_id").and_then(|v| v.as_str()) {
 801→                    if !id.is_empty() {
 802→                        return id.to_string();
 803→                    }
 804→                }
 805→            }
 806→        }
 807→    }
 808→    String::new()
 809→}
