 811→/// Discover team sessions in the project directory.
 812→pub fn discover_team_sessions(
 813→    session_path: &str,
 814→    parent_chunks: &[Chunk],
 815→) -> Result<Vec<SubagentProcess>, String> {
 816→    let specs = extract_team_specs(parent_chunks);
 817→    if specs.is_empty() {
 818→        return Ok(Vec::new());
 819→    }
 820→
 821→    let wanted: HashMap<(String, String), bool> = specs
 822→        .iter()
 823→        .map(|s| ((s.0.clone(), s.1.clone()), true))
 824→        .collect();
 825→
 826→    let project_dir = Path::new(session_path)
 827→        .parent()
 828→        .unwrap_or(Path::new(""))
 829→        .to_string_lossy()
 830→        .to_string();
 831→    let parent_base = Path::new(session_path)
 832→        .file_name()
 833→        .and_then(|n| n.to_str())
 834→        .unwrap_or("");
 835→
 836→    let entries = match fs::read_dir(&project_dir) {
 837→        Ok(e) => e,
 838→        Err(_) => return Ok(Vec::new()),
 839→    };
 840→
 841→    let mut procs = Vec::new();
 842→
 843→    for entry in entries.flatten() {
 844→        let name = entry.file_name().to_string_lossy().to_string();
 845→        if !name.ends_with(".jsonl") || name == parent_base || name.starts_with("agent-") {
 846→            continue;
 847→        }
 848→        if entry.file_type().map(|t| t.is_dir()).unwrap_or(true) {
 849→            continue;
 850→        }
 851→
 852→        let file_path = entry.path().to_string_lossy().to_string();
 853→        let metadata = match entry.metadata() {
 854→            Ok(m) => m,
 855→            Err(_) => continue,
 856→        };
 857→        if metadata.len() == 0 {
 858→            continue;
 859→        }
 860→
 861→        let (team_name, agent_name) = read_team_session_meta(&file_path);
 862→        if team_name.is_empty() || agent_name.is_empty() {
 863→            continue;
 864→        }
 865→        if !wanted.contains_key(&(team_name.clone(), agent_name.clone())) {
 866→            continue;
 867→        }
 868→
 869→        let (chunks, _, team_color) = read_subagent_session(&file_path)?;
 870→        if chunks.is_empty() {
 871→            continue;
 872→        }
 873→
 874→        procs.push(build_subagent_process(
 875→            format!("{agent_name}@{team_name}"),
 876→            file_path,
 877→            &metadata,
 878→            chunks,
 879→            String::new(),
 880→            String::new(),
 881→            team_color,
 882→        ));
 883→    }
 884→
 885→    procs.sort_by(|a, b| a.start_time.cmp(&b.start_time));
 886→    Ok(procs)
 887→}
 888→
 889→fn read_team_session_meta(path: &str) -> (String, String) {
 890→    let f = match fs::File::open(path) {
 891→        Ok(f) => f,
 892→        Err(_) => return (String::new(), String::new()),
 893→    };
 894→    let reader = BufReader::new(f);
 895→    for line_result in reader.lines() {
 896→        let line = match line_result {
 897→            Ok(l) => l,
 898→            Err(_) => break,
 899→        };
 900→        let raw: serde_json::Value = match serde_json::from_str(&line) {
 901→            Ok(v) => v,
 902→            Err(_) => continue,
 903→        };
 904→        let team_name = raw
 905→            .get("teamName")
 906→            .and_then(|v| v.as_str())
 907→            .unwrap_or("")
 908→            .to_string();
 909→        let agent_name = raw
 910→            .get("agentName")
 911→            .and_then(|v| v.as_str())
 912→            .unwrap_or("")
 913→            .to_string();
 914→        return (team_name, agent_name);
 915→    }
 916→    (String::new(), String::new())
 917→}
 918→
 919→/// Extract (team_name, agent_name) pairs from Task items in parent chunks.
 920→fn extract_team_specs(chunks: &[Chunk]) -> Vec<(String, String)> {
 921→    let mut specs = Vec::new();
 922→    for c in chunks {
 923→        if c.chunk_type != ChunkType::AI {
 924→            continue;
 925→        }
 926→        for item in &c.items {
 927→            if item.item_type != DisplayItemType::Subagent || !is_team_task(item) {
 928→                continue;
 929→            }
 930→            if let Some(Value::Object(map)) = &item.tool_input {
 931→                let tn = map.get("team_name").and_then(|v| v.as_str()).unwrap_or("");
 932→                let an = map.get("name").and_then(|v| v.as_str()).unwrap_or("");
 933→                if !tn.is_empty() && !an.is_empty() {
 934→                    specs.push((tn.to_string(), an.to_string()));
 935→                }
 936→            }
 937→        }
 938→    }
 939→    specs
 940→}
