 975→/// Scan all subagent JSONL files, inserting token snapshots into a shared
 976→/// `request_tokens` map for global requestId deduplication with the main session.
 977→/// Entries without a requestId are accumulated directly into `fallback`.
 978→pub fn scan_subagent_tokens_into(
 979→    session_path: &str,
 980→    request_tokens: &mut HashMap<String, TokenSnapshot>,
 981→    fallback: &mut TokenSnapshot,
 982→) {
 983→    let dir = subagents_dir(session_path);
 984→    let entries = match fs::read_dir(&dir) {
 985→        Ok(e) => e,
 986→        Err(_) => return,
 987→    };
 988→
 989→    for entry in entries.flatten() {
 990→        let name = entry.file_name().to_string_lossy().to_string();
 991→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
 992→            continue;
 993→        }
 994→        // Include compact files — they contain requestIds from compacted
 995→        // conversation data that may no longer be in the main session file.
 996→        let file_path = dir.join(&name);
 997→        let f = match fs::File::open(&file_path) {
 998→            Ok(f) => f,
 999→            Err(_) => continue,
1000→        };
1001→        let reader = BufReader::new(f);
1002→        for line_result in reader.lines() {
1003→            let line = match line_result {
1004→                Ok(l) => l,
1005→                Err(_) => break,
1006→            };
1007→            let raw: Value = match serde_json::from_str(&line) {
1008→                Ok(v) => v,
1009→                Err(_) => continue,
1010→            };
1011→            let entry_type = raw.get("type").and_then(|v| v.as_str()).unwrap_or("");
1012→            if entry_type != "assistant" {
1013→                continue;
1014→            }
1015→            let model = raw
1016→                .get("message")
1017→                .and_then(|m| m.get("model"))
1018→                .and_then(|v| v.as_str())
1019→                .unwrap_or("");
1020→            if model == "<synthetic>" {
1021→                continue;
1022→            }
1023→            let usage = match raw.get("message").and_then(|m| m.get("usage")) {
1024→                Some(u) => u,
1025→                None => continue,
1026→            };
1027→            let inp = usage
1028→                .get("input_tokens")
1029→                .and_then(|v| v.as_i64())
1030→                .unwrap_or(0);
1031→            let out = usage
1032→                .get("output_tokens")
1033→                .and_then(|v| v.as_i64())
1034→                .unwrap_or(0);
1035→            let cr = usage
1036→                .get("cache_read_input_tokens")
1037→                .and_then(|v| v.as_i64())
1038→                .unwrap_or(0);
1039→            let cc = usage
1040→                .get("cache_creation_input_tokens")
1041→                .and_then(|v| v.as_i64())
1042→                .unwrap_or(0);
1043→            if inp + out + cr + cc == 0 {
1044→                continue;
1045→            }
1046→            let has_stop = !raw
1047→                .get("message")
1048→                .and_then(|m| m.get("stop_reason"))
1049→                .and_then(|v| v.as_str())
1050→                .unwrap_or("")
1051→                .is_empty();
1052→            let snap = TokenSnapshot {
1053→                input: inp,
1054→                output: out,
1055→                cache_read: cr,
1056→                cache_create: cc,
1057→                model: model.to_string(),
1058→                has_stop_reason: has_stop,
1059→            };
1060→            let req_id = raw.get("requestId").and_then(|v| v.as_str()).unwrap_or("");
1061→            if !req_id.is_empty() {
1062→                insert_best_snapshot(request_tokens, req_id.to_string(), snap);
1063→            } else {
1064→                fallback.input += inp;
1065→                fallback.output += out;
1066→                fallback.cache_read += cr;
1067→                fallback.cache_create += cc;
1068→            }
1069→        }
1070→    }
1071→}
