204→/// Convert display items with subagent linking and color assignment.
205→fn convert_display_items(
206→    items: &[DisplayItem],
207→    subagents: &[SubagentProcess],
208→    color_by_tool_id: &HashMap<String, String>,
209→    pool_idx: &mut usize,
210→) -> Vec<FrontendDisplayItem> {
211→    if items.is_empty() {
212→        return Vec::new();
213→    }
214→
215→    // Build ParentTaskID -> SubagentProcess index.
216→    let proc_by_task_id: HashMap<&str, &SubagentProcess> = subagents
217→        .iter()
218→        .filter(|p| !p.parent_task_id.is_empty())
219→        .map(|p| (p.parent_task_id.as_str(), p))
220→        .collect();
221→
222→    let mut out: Vec<FrontendDisplayItem> = items
223→        .iter()
224→        .map(|it| {
225→            let mut fdi = FrontendDisplayItem {
226→                item_type: display_item_type_str(&it.item_type).to_string(),
227→                text: it.text.clone(),
228→                tool_name: it.tool_name.clone(),
229→                tool_summary: it.tool_summary.clone(),
230→                tool_category: tool_category_str(&it.tool_category).to_string(),
231→                tool_input: pretty_json(&it.tool_input),
232→                tool_result: it.tool_result.clone(),
233→                tool_error: it.tool_error,
234→                duration_ms: it.duration_ms,
235→                token_count: it.token_count,
236→                subagent_type: it.subagent_type.clone(),
237→                subagent_desc: it.subagent_desc.clone(),
238→                team_member_name: it.team_member_name.clone(),
239→                teammate_id: it.teammate_id.clone(),
240→                team_color: it.teammate_color.clone(),
241→                subagent_ongoing: false,
242→                agent_id: String::new(),
243→                subagent_messages: Vec::new(),
244→                hook_event: it.hook_event.clone(),
245→                hook_name: it.hook_name.clone(),
246→                hook_command: it.hook_command.clone(),
247→                is_orphan: it.is_orphan,
248→                subagent_prompt: String::new(),
249→            };
250→
251→            // Link subagent process if available (Subagent items and ToolCall items like Skill).
252→            if it.item_type == DisplayItemType::Subagent || !it.tool_id.is_empty() {
253→                if let Some(proc) = proc_by_task_id.get(it.tool_id.as_str()) {
254→                    fdi.subagent_ongoing =
255→                        OngoingChecker::is_subagent_ongoing_deep(proc, subagents);
256→                    fdi.agent_id = proc.id.clone();
257→                    fdi.subagent_prompt = proc.prompt.clone();
258→                    if !proc.teammate_color.is_empty() {
259→                        fdi.team_color = proc.teammate_color.clone();
260→                    }
261→                    // Convert subagent's chunks into nested messages,
262→                    // passing all processes so nested agents (e.g. Skill forked execution) can link.
263→                    fdi.subagent_messages =
264→                        chunks_to_messages(&proc.chunks, subagents, color_by_tool_id);
265→                }
266→                // Fallback: apply team color from toolUseResult data.
267→                if fdi.team_color.is_empty() {
268→                    if let Some(color) = color_by_tool_id.get(&it.tool_id) {
269→                        fdi.team_color = color.clone();
270→                    }
271→                }
272→            }
273→
274→            fdi
275→        })
276→        .collect();
277→
278→    // Assign pool colors to agent items without a team color.
279→    for di in &mut out {
280→        if di.team_color.is_empty()
281→            && (!di.subagent_messages.is_empty() || di.item_type == "Subagent")
282→        {
283→            di.team_color = TEAM_COLOR_POOL[*pool_idx % TEAM_COLOR_POOL.len()].to_string();
284→            *pool_idx += 1;
285→        }
286→    }
287→
288→    out
289→}
