/// Usage holds token counts for a single API response.
#[derive(Debug, Clone, Default, Serialize)]
pub struct Usage {
    pub input_tokens: i64,
    pub output_tokens: i64,
    pub cache_read_tokens: i64,
    pub cache_creation_tokens: i64,
}

impl Usage {
    pub fn total_tokens(&self) -> i64 {
        self.input_tokens + self.output_tokens + self.cache_read_tokens + self.cache_creation_tokens
    }
}

/// ToolCall is a tool invocation extracted from an assistant message.
#[derive(Debug, Clone, Serialize)]
pub struct ToolCall {
    pub id: String,
    pub name: String,
}

/// ContentBlock represents a single content block from a message.
#[derive(Debug, Clone, Serialize, Default)]
pub struct ContentBlock {
    pub block_type: String,
    pub text: String,
    pub tool_id: String,
    pub tool_name: String,
    pub tool_input: Option<Value>,
    pub content: String,
    pub is_error: bool,
    pub teammate_id: String,
    pub teammate_color: String,
}

/// Classified message types.
#[derive(Debug, Clone)]
pub enum ClassifiedMsg {
    User(UserMsg),
    AI(AIMsg),
    System(SystemMsg),
    Teammate(TeammateMsg),
    Compact(CompactMsg),
    Hook(HookMsg),
}

#[derive(Debug, Clone)]
pub struct UserMsg {
    pub timestamp: DateTime<Utc>,
    pub text: String,
    pub permission_mode: String,
}

#[derive(Debug, Clone)]
pub struct AIMsg {
    pub timestamp: DateTime<Utc>,
    pub model: String,
    pub text: String,
    pub thinking_count: usize,
    pub tool_calls: Vec<ToolCall>,
    pub blocks: Vec<ContentBlock>,
    pub usage: Usage,
    pub stop_reason: String,
    pub is_meta: bool,
}

#[derive(Debug, Clone)]
pub struct SystemMsg {
    pub timestamp: DateTime<Utc>,
    pub output: String,
    pub is_error: bool,

