    fn first_user_text_returns_first_user_chunk() {
        let chunks = vec![
            make_ai_chunk(),
            make_user_chunk("hello world"),
            make_user_chunk("second user"),
        ];
        assert_eq!(first_user_text(&chunks), "hello world");
    }

