    fn first_user_text_skips_empty_user_chunks() {
        let chunks = vec![make_user_chunk(""), make_user_chunk("non-empty")];
        assert_eq!(first_user_text(&chunks), "non-empty");
    }

    #[test]
    fn first_user_text_returns_empty_when_no_user_chunks() {
